  const raw = (m[1] ?? "").normalize("NFD").replace(/\p{M}/gu, "").toLowerCase();
  if (raw === "1" || raw.startsWith("basic")) return "basica";
  if (raw === "2" || raw.startsWith("tradicional")) return "tradicional";
